Docker 기반 마이크로서비스 아키텍처를 구성해 드릴게요. API Gateway + Auth + User 서비스로 나누고, 내부 네트워크로 통신합니다.

## 폴더 구조

```
microservices/
├── docker-compose.yml
├── shared/
│   └── types.ts
├── gateway/
│   ├── Dockerfile
│   ├── package.json
│   └── src/
│       └── index.ts
├── auth-service/
│   ├── Dockerfile
│   ├── package.json
│   └── src/
│       └── index.ts
└── user-service/
    ├── Dockerfile
    ├── package.json
    └── src/
        └── index.ts
```

## docker-compose.yml

```yaml
version: "3.9"

services:
  gateway:
    build: ./gateway
    ports:
      - "3000:3000"
    environment:
      - AUTH_SERVICE_URL=http://auth-service:4001
      - USER_SERVICE_URL=http://user-service:4002
      - NODE_ENV=production
    depends_on:
      auth-service:
        condition: service_healthy
      user-service:
        condition: service_healthy
    networks:
      - backend
    healthcheck:
      test: ["CMD", "curl", "-f", "http://localhost:3000/health"]
      interval: 10s
      timeout: 5s
      retries: 3

  auth-service:
    build: ./auth-service
    environment:
      - JWT_SECRET=your-secret-key-change-in-prod
      - REDIS_URL=redis://redis:6379
      - NODE_ENV=production
    depends_on:
      - redis
    networks:
      - backend
    healthcheck:
      test: ["CMD", "curl", "-f", "http://localhost:4001/health"]
      interval: 10s
      timeout: 5s
      retries: 3

  user-service:
    build: ./user-service
    environment:
      - DATABASE_URL=postgresql://app:secret@postgres:5432/users
      - NODE_ENV=production
    depends_on:
      - postgres
    networks:
      - backend
    healthcheck:
      test: ["CMD", "curl", "-f", "http://localhost:4002/health"]
      interval: 10s
      timeout: 5s
      retries: 3

  redis:
    image: redis:7-alpine
    volumes:
      - redis_data:/data
    networks:
      - backend

  postgres:
    image: postgres:16-alpine
    environment:
      POSTGRES_DB: users
      POSTGRES_USER: app
      POSTGRES_PASSWORD: secret
    volumes:
      - pg_data:/var/lib/postgresql/data
    networks:
      - backend

networks:
  backend:
    driver: bridge

volumes:
  redis_data:
  pg_data:
```

