## docker-compose.yml

```yaml
version: "3.9"

services:
  nginx:
    image: nginx:1.25-alpine
    ports:
      - "80:80"
      - "443:443"
    volumes:
      - ./nginx/nginx.conf:/etc/nginx/nginx.conf:ro
      - ./nginx/conf.d:/etc/nginx/conf.d:ro
      - certbot_certs:/etc/letsencrypt:ro
      - certbot_www:/var/www/certbot:ro
    depends_on:
      - app
    restart: unless-stopped
    networks:
      - frontend

  app:
    build: ./app
    expose:
      - "3000"
    restart: unless-stopped
    networks:
      - frontend

  certbot:
    image: certbot/certbot:latest
    volumes:
      - certbot_certs:/etc/letsencrypt
      - certbot_www:/var/www/certbot
    entrypoint: "/bin/sh -c 'trap exit TERM; while :; do certbot renew --webroot -w /var/www/certbot --quiet; sleep 12h & wait $${!}; done;'"
    restart: unless-stopped

volumes:
  certbot_certs:
  certbot_www:

networks:
  frontend:
    driver: bridge
```

## nginx/nginx.conf

```nginx
user nginx;
worker_processes auto;
error_log /var/log/nginx/error.log warn;
pid /var/run/nginx.pid;

events {
    worker_connections 1024;
    multi_accept on;
}

http {
    include /etc/nginx/mime.types;
    default_type application/octet-stream;

    # 로깅
    log_format main '$remote_addr - $remote_user [$time_local] "$request" '
                    '$status $body_bytes_sent "$http_referer" '
                    '"$http_user_agent"';
    access_log /var/log/nginx/access.log main;

    # 성능
    sendfile on;
    tcp_nopush on;
    tcp_nodelay on;
    keepalive_timeout 65;
    gzip on;
    gzip_types text/plain text/css application/json application/javascript text/xml;

    # 보안 헤더
    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header X-XSS-Protection "1; mode=block" always;
    add_header Referrer-Policy "strict-origin-when-cross-origin" always;

    # Rate Limiting
    limit_req_zone $binary_remote_addr zone=api:10m rate=10r/s;

    include /etc/nginx/conf.d/*.conf;
}
```

## nginx/conf.d/default.conf

```nginx
# HTTP → HTTPS 리다이렉트
server {
    listen 80;
    server_name example.com www.example.com;

    # Certbot ACME 챌린지
    location /.well-known/acme-challenge/ {
        root /var/www/certbot;
    }

    location / {
        return 301 https://$host$request_uri;
    }
}

# HTTPS 메인 서버
server {
    listen 443 ssl http2;
    server_name example.com www.example.com;

    # SSL 인증서
    ssl_certificate /etc/letsencrypt/live/example.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/example.com/privkey.pem;

    # SSL 보안 설정
    ssl_protocols TLSv1.2 TLSv1.3;
    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384;
    ssl_prefer_server_ciphers off;
    ssl_session_cache shared:SSL:10m;
    ssl_session_timeout 1d;
    ssl_session_tickets off;

    # HSTS
    add_header Strict-Transport-Security "max-age=63072000; includeSubDomains; preload" always;

    # 앱 프록시
    location / {
        limit_req zone=api burst=20 nodelay;
        proxy_pass http://app:3000;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;
    }

    # 정적 파일 캐싱
    location ~* \.(js|css|png|jpg|jpeg|gif|ico|svg|woff2)$ {
        proxy_pass http://app:3000;
        expires 30d;
        add_header Cache-Control "public, immutable";
    }
}
```

## scripts/init-letsencrypt.sh

```bash
#!/usr/bin/env bash
# 최초 SSL 인증서 발급 스크립트
set -euo pipefail

DOMAIN="${1:?도메인을 입력하세요 (예: example.com)}"
EMAIL="${2:?이메일을 입력하세요}"
STAGING="${3:-0}"  # 1이면 스테이징 (테스트용)

echo "=== Let's Encrypt SSL 인증서 발급 ==="
echo "도메인: $DOMAIN"
echo "이메일: $EMAIL"

# 스테이징 옵션
STAGING_ARG=""
if [ "$STAGING" = "1" ]; then
  STAGING_ARG="--staging"
  echo "모드: 스테이징 (테스트)"
fi

# 임시 자체 서명 인증서 생성 (Nginx 시작용)
echo "1) 임시 인증서 생성..."
docker compose run --rm --entrypoint "  mkdir -p /etc/letsencrypt/live/$DOMAIN &&   openssl req -x509 -nodes -newkey rsa:2048 -days 1     -keyout /etc/letsencrypt/live/$DOMAIN/privkey.pem     -out /etc/letsencrypt/live/$DOMAIN/fullchain.pem     -subj '/CN=localhost'" certbot

# Nginx 시작
echo "2) Nginx 시작..."
docker compose up -d nginx
sleep 5

# 임시 인증서 삭제
echo "3) 임시 인증서 삭제..."
docker compose run --rm --entrypoint "  rm -rf /etc/letsencrypt/live/$DOMAIN &&   rm -rf /etc/letsencrypt/archive/$DOMAIN &&   rm -rf /etc/letsencrypt/renewal/$DOMAIN.conf" certbot

# 실제 인증서 발급
echo "4) Let's Encrypt 인증서 발급..."
docker compose run --rm --entrypoint "  certbot certonly --webroot -w /var/www/certbot     $STAGING_ARG     --email $EMAIL     --agree-tos --no-eff-email     -d $DOMAIN -d www.$DOMAIN     --force-renewal" certbot

# Nginx 재시작
echo "5) Nginx 재시작..."
docker compose exec nginx nginx -s reload

echo "=== SSL 인증서 발급 완료! ==="
```

## scripts/cron-renew.sh

```bash
#!/usr/bin/env bash
# 크론 갱신 스크립트 - 호스트 크론탭에 등록
# 0 3 * * 1 /path/to/cron-renew.sh >> /var/log/certbot-renew.log 2>&1
set -euo pipefail

COMPOSE_DIR="$(cd "$(dirname "$0")/.." && pwd)"
cd "$COMPOSE_DIR"

echo "[$(date)] SSL 인증서 갱신 시작"

docker compose run --rm certbot certbot renew --quiet

# 갱신 성공 시 Nginx 리로드
if [ $? -eq 0 ]; then
  docker compose exec -T nginx nginx -s reload
  echo "[$(date)] Nginx 리로드 완료"
fi

echo "[$(date)] SSL 갱신 완료"
```

